// Retrieve the new audit result from the n8n Audit node
const newAudit = $('Generate a security audit').first().json;

// Retrieve the previous audit from Supabase (may be empty on first run)
const previousItems = $('Fetch Previous Audit').all();
let previousAudit = null;

if (previousItems.length > 0 && previousItems[0].json && previousItems[0].json.audit_data) {
  const raw = previousItems[0].json.audit_data;
  previousAudit = typeof raw === 'string' ? JSON.parse(raw) : raw;
}

// Map readable category labels to actual audit report keys
const categoryMap = {
  'Credentials': 'Credentials Risk Report',
  'Database': 'Database Risk Report',
  'File System': 'Filesystem Risk Report',
  'Nodes': 'Nodes Risk Report',
  'Instance': 'Instance Risk Report'
};

// Compare new audit against previous audit per category
const newFindings = [];
const changedFindings = [];

for (const [label, reportKey] of Object.entries(categoryMap)) {
  const newSections = (newAudit[reportKey] || {}).sections || [];
  const prevSections = previousAudit ? ((previousAudit[reportKey] || {}).sections || []) : [];

  for (const section of newSections) {
    const prevSection = prevSections.find(s => s.title === section.title);

    // Build affected list based on category and location type
    let affected = [];
    if (section.location) {
      if (label === 'Nodes') {
        // Group by workflow name with node count
        const workflowCounts = {};
        for (const l of section.location) {
          const name = l.workflowName || l.nodeType || l.name || JSON.stringify(l);
          workflowCounts[name] = (workflowCounts[name] || 0) + 1;
        }
        affected = Object.entries(workflowCounts).map(([name, count]) =>
          count > 1 ? `${name} (${count} nodes)` : name
        );
      } else if (label === 'Instance') {
        // Webhooks have a path, other instance items have a name
        affected = section.location.map(l =>
          l.webhookPath ? `${l.workflowName} — ${l.webhookPath}` :
          l.name || l.nodeType || JSON.stringify(l)
        );
      } else {
        affected = section.location.map(l =>
          l.name || l.nodeType || l.packageUrl || JSON.stringify(l)
        );
      }
    }

    // Format version info dynamically from description and nextVersions
    let extra = null;
    if (section.nextVersions) {
      extra = `${section.description}\nAvailable updates: ${section.nextVersions.map(v => v.name).join(' / ')}`;
    }

    // Format security settings dynamically
    if (section.settings) {
      const s = section.settings;
      const lines = [];
      if (s.features) {
        for (const [key, value] of Object.entries(s.features)) {
          lines.push(`• ${key}: ${value ? 'enabled' : 'disabled'}`);
        }
      }
      if (s.nodes) {
        for (const [key, value] of Object.entries(s.nodes)) {
          lines.push(`• ${key}: ${value || 'none'}`);
        }
      }
      if (s.telemetry) {
        for (const [key, value] of Object.entries(s.telemetry)) {
          lines.push(`• ${key}: ${value ? 'enabled' : 'disabled'}`);
        }
      }
      extra = lines.join('\n');
    }

    const finding = {
      category: label,
      type: 'NEW',
      title: section.title,
      description: section.description,
      recommendation: section.recommendation,
      affected,
      extra
    };

    if (!prevSection) {
      newFindings.push(finding);
    } else if (JSON.stringify(prevSection) !== JSON.stringify(section)) {
      changedFindings.push({ ...finding, type: 'CHANGED' });
    }
  }
}

// Return findings and a boolean for the IF node
return [{
  json: {
    newAudit,
    newFindings,
    changedFindings,
    hasChanges: newFindings.length > 0 || changedFindings.length > 0
  }
}];
